import{_ as a,o as r,c as n,ah as t}from"./chunks/framework.DsjyFzT5.js";const b=JSON.parse('{"title":"互联网 / 开发 / 工作术语","description":"","frontmatter":{"title":"互联网 / 开发 / 工作术语","date":"2021-01-01T00:00:00.000Z","category":"Wiki","tags":["Wiki"]},"headers":[],"relativePath":"_post/wiki/code-words.md","filePath":"_post/wiki/code-words.md"}'),s={name:"_post/wiki/code-words.md"};function l(i,e,o,c,p,h){return r(),n("div",null,[...e[0]||(e[0]=[t(`<h1 id="互联网-开发-工作术语" tabindex="-1">互联网 / 开发 / 工作术语 <a class="header-anchor" href="#互联网-开发-工作术语" aria-label="Permalink to &quot;互联网 / 开发 / 工作术语&quot;">​</a></h1><h2 id="开发名词" tabindex="-1">开发名词 <a class="header-anchor" href="#开发名词" aria-label="Permalink to &quot;开发名词&quot;">​</a></h2><ul><li>dsl(domain-specific language): 同时具备描述能力和逻辑能力的语言[1][2]。</li><li>CI/CD(Continuous Integration/Continuous Delivery): 持续集成/持续交付/持续部署[3]，通过软件开发的持续方法，您可以持续构建、测试和部署迭代代码更改[7]</li><li>pr(Pull Request): 和<code>merge request</code>一个意思，<code>merge request</code> gitlab 常用，拉取代码修改代码发起合并请求。</li><li>ssr：服务端渲染</li><li>公钥私钥、非对称加密：非对称加密算法需要两个密钥：公开密钥（publickey:简称公钥）和私有密钥（privatekey:简称私钥）。公钥与私钥是一对，如果用公钥对数据进行加密，只有用对应的私钥才能解密。因为加密和解密使用的是两个不同的密钥[5]</li><li>CLI（Command Line Interface）：命令行界面</li></ul><h2 id="工作名词" tabindex="-1">工作名词 <a class="header-anchor" href="#工作名词" aria-label="Permalink to &quot;工作名词&quot;">​</a></h2><ul><li>ROI（Return On Investment）：投资回报率，它是指通过投资而应返回的价值，它涵盖了企业的获利目标，投资利润率。在营销场景中，一般指代营销的投资回报率/投入产出比。狭义的投入指代营销费用，广义的投入还包括公司的运维成本，给用户的补贴红包等。产出即收入，收入包括广告收入，直播收入等。</li></ul><h2 id="前端名词" tabindex="-1">前端名词 <a class="header-anchor" href="#前端名词" aria-label="Permalink to &quot;前端名词&quot;">​</a></h2><h3 id="网页性能指标" tabindex="-1">网页性能指标 <a class="header-anchor" href="#网页性能指标" aria-label="Permalink to &quot;网页性能指标&quot;">​</a></h3><blockquote><p>🔗 参考链接：<a href="https://web.dev/articles/user-centric-performance-metrics?hl=zh-cn" target="_blank" rel="noreferrer">https://web.dev/articles/user-centric-performance-metrics?hl=zh-cn</a></p></blockquote><ul><li><strong><a href="https://web.dev/articles/fcp?hl=zh-cn" target="_blank" rel="noreferrer">First Contentful Paint (FCP)</a></strong>：衡量从网页开始加载到网页任何部分内容呈现在屏幕上所用的时间。</li><li><strong><a href="https://web.dev/articles/lcp?hl=zh-cn" target="_blank" rel="noreferrer">Largest Contentful Paint (LCP)</a></strong>：衡量从网页开始加载到最大的文本块或图片元素在屏幕上呈现所用的时间。</li><li><strong><a href="https://web.dev/articles/fid?hl=zh-cn" target="_blank" rel="noreferrer">First Input Delay (FID)</a></strong>：用于衡量从用户首次与您的网站互动（点击链接、点按按钮或使用由 JavaScript 提供支持的自定义控件）到浏览器实际能够响应此次互动所用的时间。<em>（<a href="https://web.dev/articles/user-centric-performance-metrics?hl=zh-cn#in_the_field" target="_blank" rel="noreferrer">字段</a>）</em></li><li><strong><a href="https://web.dev/articles/inp?hl=zh-cn" target="_blank" rel="noreferrer">Interaction to Next Paint (INP)</a></strong>：测量与网页进行的每次点按、点击或键盘交互的延迟时间，并根据交互次数选择页面中最差的互动延迟时间（或接近最高延迟时间）作为单个有代表性的值，以描述网页的整体响应速度。</li><li><strong><a href="https://web.dev/articles/tti?hl=zh-cn" target="_blank" rel="noreferrer">可交互时间 (TTI)</a></strong>：衡量从网页开始加载到视觉呈现、其初始脚本（如有）已加载且能够快速可靠地响应用户输入的时间。<em>（<a href="https://web.dev/articles/user-centric-performance-metrics?hl=zh-cn#in_the_lab" target="_blank" rel="noreferrer">实验</a>）</em></li><li><strong><a href="https://web.dev/articles/tbt?hl=zh-cn" target="_blank" rel="noreferrer">总阻塞时间 (TBT)</a></strong>：测量 FCP 和 TTI 之间的总阻塞时间，这段时间内主线程处于阻塞状态的时间足够长，足以阻止输入响应。<em>（<a href="https://web.dev/articles/user-centric-performance-metrics?hl=zh-cn#in_the_lab" target="_blank" rel="noreferrer">实验</a>）</em></li><li><strong><a href="https://web.dev/articles/cls?hl=zh-cn" target="_blank" rel="noreferrer">Cumulative Layout Shift (CLS)</a></strong>：衡量从页面开始加载到其<a href="https://developer.chrome.com/blog/page-lifecycle-api/?hl=zh-cn" target="_blank" rel="noreferrer">生命周期状态</a>更改为隐藏之间发生的所有意外布局偏移的累计分数。</li><li><strong><a href="https://web.dev/articles/ttfb?hl=zh-cn" target="_blank" rel="noreferrer">首字节时间 (TTFB)</a></strong>：测量网络使用资源的第一个字节响应用户请求所需的时间。</li></ul><h2 id="uri-uniform-resource-identifier-6" tabindex="-1">URI（Uniform Resource Identifier）[6] <a class="header-anchor" href="#uri-uniform-resource-identifier-6" aria-label="Permalink to &quot;URI（Uniform Resource Identifier）[6]&quot;">​</a></h2><p>统一资源标志符，用于标志某一互联网资源名称的字符串，该种标志允许用户对网络中（一般指万维网）的资源通过特定的协议进行交互操作。</p><p>通用格式：</p><p>eg:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>                    hierarchical part</span></span>
<span class="line"><span>        ┌───────────────────┴─────────────────────┐</span></span>
<span class="line"><span>                    authority               path</span></span>
<span class="line"><span>        ┌───────────────┴───────────────┐┌───┴────┐</span></span>
<span class="line"><span>  abc://username:password@example.com:123/path/data?key=value&amp;key2=value2#fragid1</span></span>
<span class="line"><span>  └┬┘   └───────┬───────┘ └────┬────┘ └┬┘           └─────────┬─────────┘ └──┬──┘</span></span>
<span class="line"><span>scheme  user information     host     port                  query         fragment</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  urn:example:mammal:monotreme:echidna</span></span>
<span class="line"><span>  └┬┘ └──────────────┬───────────────┘</span></span>
<span class="line"><span>scheme              path</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br></div></div><h2 id="数据分析相关名词" tabindex="-1">数据分析相关名词 <a class="header-anchor" href="#数据分析相关名词" aria-label="Permalink to &quot;数据分析相关名词&quot;">​</a></h2><ul><li>UGC(User Generated Content): 用户原创内容</li></ul><h2 id="参考文章" tabindex="-1">参考文章 <a class="header-anchor" href="#参考文章" aria-label="Permalink to &quot;参考文章&quot;">​</a></h2><p>[1] <a href="https://zhuanlan.zhihu.com/p/24800713" target="_blank" rel="noreferrer">五分钟，科普下 dsl</a> [2] <a href="https://blog.csdn.net/lpjishu/article/details/72530910" target="_blank" rel="noreferrer">Android 的 gradle 用到的 DSL 语言是个什么鬼?</a> [3] <a href="https://linux.cn/article-9926-1.html?pr" target="_blank" rel="noreferrer">什么是CI/CD</a> [4] <a href="https://www.zhihu.com/question/355235592" target="_blank" rel="noreferrer">开发中经常提及的Pr是什么意思？</a><br> [5] <a href="https://baike.baidu.com/item/%E9%9D%9E%E5%AF%B9%E7%A7%B0%E5%8A%A0%E5%AF%86%E7%AE%97%E6%B3%95/1208652" target="_blank" rel="noreferrer">百度百科-非对称加密算法</a><br> [6] <a href="https://zh.wikipedia.org/wiki/%E7%BB%9F%E4%B8%80%E8%B5%84%E6%BA%90%E6%A0%87%E5%BF%97%E7%AC%A6" target="_blank" rel="noreferrer">维基百科-URI</a> [7] <a href="https://gitlab.cn/docs/jh/ci/introduction/" target="_blank" rel="noreferrer">gitlab:CI/CD概念</a></p>`,18)])])}const u=a(s,[["render",l]]);export{b as __pageData,u as default};
